import{_ as a,o as i,c as e,ag as t}from"./chunks/framework.DlJzNSsD.js";const k=JSON.parse('{"title":"Installation and updates","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/installation.md","filePath":"getting-started/installation.md","lastUpdated":1778766855000}'),n={name:"getting-started/installation.md"};function l(h,s,r,p,o,d){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="installation-and-updates" tabindex="-1">Installation and updates <a class="header-anchor" href="#installation-and-updates" aria-label="Permalink to &quot;Installation and updates&quot;">​</a></h1><p>Clawterm ships pre-built binaries for macOS (Apple Silicon and Intel), Windows (x64), and Linux (x64, <code>.deb</code> and <code>.AppImage</code>).</p><h2 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h2><p>One-liner installer (downloads the latest DMG, verifies the SHA-256 checksum against the release&#39;s <code>checksums-universal-apple-darwin.txt</code>, copies <code>Clawterm.app</code> into <code>/Applications</code>, and clears the quarantine flag):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/clawterm/clawterm/main/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>If you&#39;d rather install by hand, download <code>Clawterm_&lt;version&gt;_universal.dmg</code> from the <a href="https://github.com/clawterm/clawterm/releases/latest" target="_blank" rel="noreferrer">latest release</a> — a single universal build that runs on both Apple Silicon and Intel Macs.</p><p>Mount the DMG and drag <code>Clawterm.app</code> into <code>/Applications</code>.</p><blockquote><p><strong>Gatekeeper note:</strong> Clawterm is not yet Apple-notarized. If macOS refuses to launch it, clear the quarantine flag once:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications/Clawterm.app</span></span></code></pre></div><p>Tracking issue: <a href="https://github.com/clawterm/clawterm/issues/378" target="_blank" rel="noreferrer">#378</a>.</p></blockquote><h2 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">raw.githubusercontent.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">clawterm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">clawterm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">main</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p>The script downloads the latest <code>Clawterm_&lt;version&gt;_x64-setup.exe</code>, verifies the SHA-256 checksum, and runs the installer.</p><p>You can also download the installer manually from the <a href="https://github.com/clawterm/clawterm/releases/latest" target="_blank" rel="noreferrer">latest release</a>.</p><blockquote><p><strong>SmartScreen note:</strong> Clawterm is not yet Authenticode-signed. Windows may show a SmartScreen warning the first time you run the installer. Click <strong>More info → Run anyway</strong>. Tracking issue: <a href="https://github.com/clawterm/clawterm/issues/379" target="_blank" rel="noreferrer">#379</a>.</p></blockquote><h2 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h2><p>Download either package from the <a href="https://github.com/clawterm/clawterm/releases/latest" target="_blank" rel="noreferrer">latest release</a>:</p><ul><li>Debian/Ubuntu → <code>Clawterm_&lt;version&gt;_amd64.deb</code> — install with <code>sudo apt install ./Clawterm_&lt;version&gt;_amd64.deb</code></li><li>Other distros → <code>Clawterm_&lt;version&gt;_amd64.AppImage</code> — <code>chmod +x</code> and run directly</li></ul><h3 id="building-from-source" tabindex="-1">Building from source <a class="header-anchor" href="#building-from-source" aria-label="Permalink to &quot;Building from source&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/clawterm/clawterm.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clawterm</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tauri</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Requirements:</p><ul><li><a href="https://rustup.rs/" target="_blank" rel="noreferrer">Rust</a></li><li><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> 18+</li><li>Tauri system dependencies — see the <a href="https://v2.tauri.app/start/prerequisites/" target="_blank" rel="noreferrer">Tauri prerequisites guide</a> for your distro</li></ul><p>The built binary lands in <code>src-tauri/target/release/</code>.</p><h2 id="verifying-checksums-manually" tabindex="-1">Verifying checksums manually <a class="header-anchor" href="#verifying-checksums-manually" aria-label="Permalink to &quot;Verifying checksums manually&quot;">​</a></h2><p>Each platform&#39;s release artifacts ship with a <code>checksums-&lt;target&gt;.txt</code> file:</p><ul><li>macOS → <code>checksums-universal-apple-darwin.txt</code></li><li>Windows → <code>checksums-x86_64-pc-windows-msvc.txt</code></li><li>Linux → <code>checksums-x86_64-unknown-linux-gnu.txt</code></li></ul><p><strong>macOS / Linux:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shasum</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 256</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checksums-universal-apple-darwin.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ignore-missing</span></span></code></pre></div><p><strong>Windows (PowerShell):</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-FileHash</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Algorithm SHA256 .\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Clawterm_1.2.0_x64-setup.exe</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Compare the hash against the matching line in checksums-x86_64-pc-windows-msvc.txt</span></span></code></pre></div><p>The one-liner installers above do this automatically and abort on mismatch.</p><h2 id="updates" tabindex="-1">Updates <a class="header-anchor" href="#updates" aria-label="Permalink to &quot;Updates&quot;">​</a></h2><p>Clawterm checks for updates automatically once an hour by default. When a new version is available, a dialog appears with the release notes and an <strong>Install</strong> button.</p><p>Update behaviour is controlled by the <code>updates</code> section in <code>config.json</code> — see <a href="./../reference/configuration#updates">configuration.md → updates</a> for the full schema. Summary:</p><ul><li><code>updates.autoCheck</code> — turn auto-checking on or off</li><li><code>updates.checkIntervalMs</code> — how often to poll (5 minutes to 24 hours)</li><li><code>updates.autoInstall</code> — silently install updates without prompting</li></ul><p>You can also trigger a manual update check from the settings page.</p><h3 id="re-running-the-install-script" tabindex="-1">Re-running the install script <a class="header-anchor" href="#re-running-the-install-script" aria-label="Permalink to &quot;Re-running the install script&quot;">​</a></h3><p>Running the same one-liner again performs an in-place upgrade:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/clawterm/clawterm/main/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>If the installed version already matches the latest release, the script exits without doing any work.</p><h2 id="uninstalling" tabindex="-1">Uninstalling <a class="header-anchor" href="#uninstalling" aria-label="Permalink to &quot;Uninstalling&quot;">​</a></h2><p><strong>macOS:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/clawterm/clawterm/main/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --uninstall</span></span></code></pre></div><p>This removes <code>/Applications/Clawterm.app</code> and prompts before deleting <code>~/.config/clawterm</code> (so your config survives unless you say otherwise).</p><p><strong>Windows:</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">raw.githubusercontent.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">clawterm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">clawterm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">main</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ArgumentList </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;--uninstall&#39;</span></span></code></pre></div><p>Or uninstall from <strong>Settings → Apps</strong> like any other Windows app. The config at <code>%APPDATA%\\clawterm</code> is left in place unless you remove it manually.</p><p><strong>Manual cleanup paths:</strong></p><table tabindex="0"><thead><tr><th>Platform</th><th>App</th><th>Config</th></tr></thead><tbody><tr><td>macOS</td><td><code>/Applications/Clawterm.app</code></td><td><code>~/.config/clawterm/</code></td></tr><tr><td>Windows</td><td>Uninstalled via Add/Remove Programs</td><td><code>%APPDATA%\\clawterm\\</code></td></tr><tr><td>Linux</td><td><code>/usr/bin/clawterm</code> (<code>.deb</code>) or wherever you placed the <code>.AppImage</code></td><td><code>~/.config/clawterm/</code></td></tr></tbody></table>`,47)])])}const g=a(n,[["render",l]]);export{k as __pageData,g as default};
